function render(t, context) {
  const { ctx, width: w, height: h, progress } = context;
  const ease = 1 - Math.pow(1 - progress, 3);
  ctx.fillStyle = '#07090f';
  ctx.fillRect(0, 0, w, h);
  ctx.save();
  ctx.translate(w / 2, h / 2);
  for (let i = 0; i < 36; i++) {
    const a = i / 36 * Math.PI * 2 + t * 0.35;
    const r = 110 + i * 5 + Math.sin(t * 1.2 + i) * 18;
    const x = Math.cos(a) * r;
    const y = Math.sin(a) * r * 0.42;
    ctx.globalAlpha = 0.18 + ease * 0.45;
    ctx.fillStyle = i % 3 === 0 ? '#7bd88f' : i % 3 === 1 ? '#79d9ff' : '#ff5c8a';
    ctx.beginPath();
    ctx.arc(x, y, 3 + (i % 4), 0, Math.PI * 2);
    ctx.fill();
  }
  ctx.globalAlpha = 1;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillStyle = '#f7f1df';
  ctx.font = '800 82px Arial, sans-serif';
  ctx.fillText('UIV Runtime', 0, -32 + (1 - ease) * 28);
  ctx.fillStyle = '#9fb6c9';
  ctx.font = '26px Arial, sans-serif';
  ctx.fillText('custom-code video, timed by segments', 0, 48);
  ctx.restore();
}

