function render(t, context) {
  const { ctx, width: w, height: h, progress } = context;
  ctx.fillStyle = '#0b1018';
  ctx.fillRect(0, 0, w, h);
  const left = 130;
  const right = w - 130;
  const y = h / 2;
  ctx.strokeStyle = '#1d3045';
  ctx.lineWidth = 2;
  for (let i = 0; i < 9; i++) {
    const x = left + (right - left) * i / 8;
    ctx.beginPath();
    ctx.moveTo(x, 120);
    ctx.lineTo(x, h - 120);
    ctx.stroke();
  }
  ctx.strokeStyle = '#f2aa4c';
  ctx.lineWidth = 8;
  ctx.lineCap = 'round';
  ctx.beginPath();
  ctx.moveTo(left, y);
  ctx.lineTo(left + (right - left) * progress, y);
  ctx.stroke();
  const labels = ['0s', '3s', '6s', '9s', '12s'];
  ctx.font = '18px Arial, sans-serif';
  ctx.fillStyle = '#9fb6c9';
  ctx.textAlign = 'center';
  for (let i = 0; i < labels.length; i++) {
    const x = left + (right - left) * i / (labels.length - 1);
    ctx.fillText(labels[i], x, y + 52);
  }
  const blocks = [
    ['identity', '#79d9ff'], ['timeline', '#f2aa4c'], ['orchestration', '#7bd88f'], ['export', '#ff5c8a']
  ];
  ctx.font = '700 28px Arial, sans-serif';
  blocks.forEach((block, i) => {
    const x = left + (right - left) * (i + 0.5) / blocks.length;
    ctx.fillStyle = block[1];
    ctx.globalAlpha = progress > i / blocks.length ? 1 : 0.25;
    ctx.fillText(block[0], x, y - 54);
  });
  ctx.globalAlpha = 1;
  ctx.fillStyle = '#f7f1df';
  ctx.font = '800 46px Arial, sans-serif';
  ctx.fillText('Segmented Timeline Engine', w / 2, 116);
}

function render(t, context) {
  const { ctx, width: w, height: h, progress } = context;
  ctx.fillStyle = '#09110f';
  ctx.fillRect(0, 0, w, h);
  const cx = w / 2;
  const cy = h / 2;
  const nodes = [
    ['scene graph', -310, -80, '#79d9ff'],
    ['timeline', 0, -150, '#f2aa4c'],
    ['scheduler', 310, -80, '#7bd88f'],
    ['adapters', -210, 120, '#ff5c8a'],
    ['export frames', 210, 120, '#c7a6ff']
  ];
  ctx.lineWidth = 3;
  ctx.strokeStyle = 'rgba(223,233,245,.32)';
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const a = nodes[i];
      const b = nodes[j];
      ctx.globalAlpha = 0.15 + progress * 0.45;
      ctx.beginPath();
      ctx.moveTo(cx + a[1], cy + a[2]);
      ctx.lineTo(cx + b[1], cy + b[2]);
      ctx.stroke();
    }
  }
  ctx.globalAlpha = 1;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  nodes.forEach((node, i) => {
    const pulse = 1 + Math.sin(t * 3 + i) * 0.04;
    const x = cx + node[1];
    const y = cy + node[2];
    ctx.fillStyle = node[3];
    ctx.beginPath();
    ctx.roundRect(x - 108 * pulse, y - 31 * pulse, 216 * pulse, 62 * pulse, 16);
    ctx.fill();
    ctx.fillStyle = '#061014';
    ctx.font = '700 22px Arial, sans-serif';
    ctx.fillText(node[0], x, y + 1);
  });
  ctx.fillStyle = '#f7f1df';
  ctx.font = '800 44px Arial, sans-serif';
  ctx.fillText('Multi-Library Orchestration', cx, 94);
}

