export default {
  render(t, context) {
    const { ctx, width: w, height: h, progress } = context;
    const ease = 1 - Math.pow(1 - progress, 4);
    ctx.fillStyle = '#090a12';
    ctx.fillRect(0, 0, w, h);
    ctx.save();
    ctx.translate(w / 2, h / 2);
    ctx.strokeStyle = '#f2aa4c';
    ctx.lineWidth = 6;
    ctx.globalAlpha = 0.45 + ease * 0.55;
    ctx.beginPath();
    ctx.roundRect(-310, -142, 620, 284, 34);
    ctx.stroke();
    for (let i = 0; i < 24; i++) {
      const p = (i / 24 + progress) % 1;
      const x = -280 + p * 560;
      const y = -94 + Math.sin(p * Math.PI * 2 + t * 2) * 54;
      ctx.fillStyle = i % 2 ? '#79d9ff' : '#7bd88f';
      ctx.globalAlpha = 0.18 + p * 0.65;
      ctx.fillRect(x, y, 18, 18);
    }
    ctx.globalAlpha = 1;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = '#f7f1df';
    ctx.font = '800 58px Arial, sans-serif';
    ctx.fillText('Deterministic Video Export', 0, -18);
    ctx.fillStyle = '#9fb6c9';
    ctx.font = '24px Arial, sans-serif';
    ctx.fillText('segment-aware frames + custom-code diagnostics', 0, 50);
    ctx.restore();
  }
}
